const data = $input.first().json || {};
const context = data.context || {};
const router = data.router_output || {};
const store = context.store || {};
const website = String(store.store_website_url || 'https://technostoresalta.com').trim();
const recentMessages = Array.isArray(context.recent_messages) ? context.recent_messages : [];
const candidateProducts = Array.isArray(context.candidate_products) ? context.candidate_products : [];
const usedIphoneCandidates = Array.isArray(context.used_iphone_candidates) ? context.used_iphone_candidates : [];
const interestedProductKey = String(context.customer?.interested_product || '').trim();
const websiteHost = website.replace(/^https?:\/\//, '').replace(/\/$/, '').toLowerCase();

const recentThread = recentMessages
  .slice(-10)
  .map((message) => ({
    role: message.role === 'bot' ? 'assistant' : 'user',
    message: String(message.message || '').trim(),
  }))
  .filter((message) => message.message);

const focusedProductKey = router.search_mode === 'thread_context' ? interestedProductKey || null : null;
const recentStoreUrlMentions = recentThread.filter(
  (message) => message.role === 'assistant' && websiteHost && message.message.toLowerCase().includes(websiteHost)
).length;

const curatedCandidates = candidateProducts.slice(0, router.route_key === 'exact_product_quote' ? 4 : 5).map((product) => ({
  product_key: product.product_key,
  product_name: product.product_name,
  product_url: product.product_url || null,
  condition: product.condition,
  storage_gb: product.storage_gb,
  color: product.color,
  in_stock: product.in_stock,
  delivery_days: product.delivery_days,
  price_ars: product.price_ars,
  promo_price_ars: product.promo_price_ars,
  price_usd: product.price_usd,
  image_url: product.image_url,
}));

const curatedUsedIphones = usedIphoneCandidates
  .slice(0, router.should_offer_used_iphones === true ? 4 : 2)
  .map((item) => ({
    id: item.id,
    model_name: item.model_name,
    family_number: item.family_number,
    tier_key: item.tier_key,
    storage_gb: item.storage_gb,
    color: item.color,
    battery_health_pct: item.battery_health_pct,
    battery_note: item.battery_note,
    condition: item.condition,
    sale_price_usd: item.sale_price_usd,
  }));

const promptPayload = {
  route_key: router.route_key,
  search_mode: router.search_mode,
  should_offer_store_url: router.should_offer_store_url === true,
  should_offer_used_iphones: router.should_offer_used_iphones === true,
  first_interaction: recentThread.length <= 1,
  focused_product_key: focusedProductKey,
  recent_store_url_mentions: recentStoreUrlMentions,
  user_message: String(data.user_message || ''),
  recent_thread: recentThread,
  customer: context.customer || {},
  store: {
    store_location_name: store.store_location_name || 'TechnoStore Salta',
    store_address: store.store_address || '',
    store_payment_methods: store.store_payment_methods || '',
    store_shipping_policy: store.store_shipping_policy || '',
    store_warranty_new: store.store_warranty_new || '',
    store_warranty_used: store.store_warranty_used || '',
    store_website_url: website,
  },
  used_iphone_catalog: context.used_iphone_catalog || {},
  candidate_products: curatedCandidates,
  used_iphone_candidates: curatedUsedIphones,
};

const prompt = [
  'Respondé al siguiente turno comercial usando SOLO los datos provistos.',
  'La prioridad absoluta es el pedido actual del usuario. No te quedes pegado a un producto viejo del hilo si el usuario cambió de modelo, marca o versión.',
  'Usá recent_thread y focused_product_key solo para continuidad cuando el usuario diga "ese", "el anterior", "y en cuotas?", "y la entrega?" o similares sin nombrar un modelo nuevo.',
  'Si el usuario menciona un modelo o marca concreta, respondé primero sobre ese pedido y no lo cambies por otro equipo salvo que pida alternativas, comparación o que ese modelo no exista y primero lo aclares.',
  'Si el usuario menciona dos equipos, comparalos o respondé sobre ambos sin perderte en uno solo.',
  'Formateá los precios de candidate_products en ARS con separadores argentinos, por ejemplo ARS 1.165.080.',
  'Si el usuario pregunta si un color puntual está disponible, respondé que sí, ese color está disponible.',
  'Los used_iphone_candidates usan USD. Si los mencionás, respetá sale_price_usd tal cual y mostralos como USD 529. No inventes conversión a ARS.',
  'Si should_offer_used_iphones es true y hay used_iphone_candidates, podés ofrecer 1 a 3 opciones usadas como alternativa más accesible.',
  'Si el usuario pidió un modelo exacto, respondé primero sobre ese pedido. Solo después abrí la puerta a usados si ayuda por presupuesto, exploración o porque candidate_products no muestra un match claro.',
  'Si candidate_products no tiene un match claro para un iPhone pedido pero used_iphone_candidates sí, podés aclararlo de forma simple y ofrecer esas opciones usadas.',
  'No prometas ni ofrezcas un link de pago directo en una consulta normal de producto. Solo mencioná un link real si ya existe en el contexto del pedido web.',
  'No compartas technostoresalta.com por inercia. Solo compartí una URL si realmente ayuda en este turno y evitá repetirla si ya apareció en el hilo.',
  'Si route_key es exact_product_quote y candidate_products[0].product_url existe, compartí ese link específico como máximo una vez y de forma natural. No mandes la home del sitio en ese caso.',
  'Si el usuario está explorando o comparando, no empujes pago, envío, retiro ni cierre de compra por defecto.',
  'Si preguntan por pago, cuotas, envío o cómo comprar, respondé eso de forma clara y tranquila, sin sonar insistente. No aceptamos compras con DNI.',
  'No termines todas las respuestas con una pregunta. Solo hacelo si ayuda a aclarar algo real o a avanzar sin presión.',
  'Devolvé SOLO JSON válido.',
  'Esquema esperado:',
  JSON.stringify({
    reply_text: 'string',
    selected_product_keys: ['string'],
    actions: ['attach_store_url'],
    state_delta: {
      intent_key: 'price_inquiry',
      funnel_stage: 'interested',
      lead_score_delta: 8,
      share_store_location: false,
      selected_product_keys: ['string'],
      tags_to_add: ['catalog_interest'],
      tags_to_remove: [],
      payment_method_key: null,
      summary: 'string',
    },
  }),
  'Datos del turno:',
  JSON.stringify(promptPayload, null, 2),
].join('\n\n');

return [{
  json: {
    ...data,
    responder_model_name: String($env.GROQ_MODEL_SALES || 'llama3-8b-8192'),
    chatInput: prompt,
  }
}];

const base = $('Build Sales Prompt').first().json || {};
const raw = $input.first().json || {};

const fallbackExactCandidate = Array.isArray(base.context?.candidate_products) ? base.context.candidate_products[0] : null;
const rawText = String(raw.output || raw.text || '').trim();
const normalizedUserMessage = String(base.user_message || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const asksColorAvailability = /\b(blanco|blanca|white|naranja|orange|azul|blue|negro|negra|black|gris|gray|plata|silver|rosa|pink|verde|green|violeta|purple|dorado|gold)\b/.test(normalizedUserMessage) && /\b(hay|tenes|tienen|disponible|stock|queda|viene)\b/.test(normalizedUserMessage);
const normalizedUserMessage = String(base.user_message || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const asksBuyingStep = /(pago|pagar|comprar|compra|link de pago|transferencia|cuotas|envio|retiro|como compro|como comprar|senia|seña)/.test(normalizedUserMessage);

let parsed = null;
try {
  parsed = JSON.parse(rawText);
} catch (error) {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (innerError) {
      parsed = null;
    }
  }
}

const formatArs = (value) => {
  const amount = Number(value);
  if (!Number.isFinite(amount)) return null;
  return new Intl.NumberFormat('es-AR', { maximumFractionDigits: 0 }).format(amount);
};

const fallbackReply = (() => {
  if (base.router_output?.route_key === 'exact_product_quote' && fallbackExactCandidate) {
    const priceArs = formatArs(fallbackExactCandidate.promo_price_ars || fallbackExactCandidate.price_ars);
    return 'Sí, tengo ' + fallbackExactCandidate.product_name + '. Queda en ARS ' + priceArs + '.';
  }
  return 'Sí, te ayudo por acá. Decime qué modelo buscás y te paso precio y disponibilidad.';
})();

const selected = Array.isArray(parsed?.selected_product_keys) ? parsed.selected_product_keys : [];
const actions = Array.isArray(parsed?.actions) ? parsed.actions : [];
const stateDelta = parsed?.state_delta && typeof parsed.state_delta === 'object' ? parsed.state_delta : {};
let replyText = String(parsed?.reply_text || fallbackReply).replace(/\s+/g, ' ').trim();

const priceCandidates = Array.isArray(base.context?.candidate_products) ? base.context.candidate_products : [];
for (const product of priceCandidates) {
  for (const rawPrice of [product?.promo_price_ars, product?.price_ars]) {
    const numericPrice = Number(rawPrice);
    const formattedPrice = formatArs(numericPrice);
    if (!Number.isFinite(numericPrice) || !formattedPrice) continue;
    const rawString = String(Math.trunc(numericPrice));
    replyText = replyText
      .replace(new RegExp('ARS\\s*' + rawString + '(?!\\d)', 'g'), 'ARS ' + formattedPrice)
      .replace(new RegExp('\\$\\s*' + rawString + '(?!\\d)', 'g'), 'ARS ' + formattedPrice)
      .replace(new RegExp('(?<!\\d)' + rawString + '(?!\\d)', 'g'), formattedPrice);
  }
}

if (base.router_output?.route_key === 'exact_product_quote') {
  replyText = replyText
    .replace(/Si quer[eé]s,\s*te paso el link de pago[^.]*\.?/gi, 'Si querés, te paso más detalles.')
    .replace(/¿Te gustar[ií]a conocer las opciones de pago\??/gi, '')
    .replace(/¿Te gustar[ií]a saber las opciones de pago\??/gi, '')
    .replace(/¿Te gustar[ií]a que te ayude a (?:coordinar|avanzar|iniciar)[^?]*\??/gi, '')
    .replace(/¿Hay alg[uú]n otro modelo o marca que te interese\??/gi, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (!asksBuyingStep) {
    replyText = replyText
      .replace(/Para avanzar con la compra[^.]*\.?/gi, '')
      .replace(/Pod[eé]s iniciar la compra[^.]*\.?/gi, '')
      .replace(/Si prefer[ií]s avanzar online[^.]*\.?/gi, '')
      .replace(/\s+/g, ' ')
      .trim();
  }
}

if (asksColorAvailability && !/^si[,\s]/i.test(replyText) && !/^sí[,\s]/i.test(replyText)) {
  replyText = ('Sí, ese color está disponible. ' + replyText).replace(/\s+/g, ' ').trim();
}

return [{
  json: {
    ...base,
    responder_output: {
      route_key: base.router_output?.route_key || 'generic_sales',
      reply_text: replyText,
      selected_product_keys: selected,
      actions,
      state_delta: stateDelta,
    },
    responder_provider_name: 'groq',
    responder_model_name: base.responder_model_name || 'llama3-8b-8192',
    responder_raw_text: rawText,
  }
}];
